  const svg = document.querySelector("[animated-graph-wrapper] svg");
  const chartLine = document.querySelector(".chart-line");
  const lineLength = chartLine.getTotalLength();

  gsap.set(".grid-line", { opacity: 0 });
  gsap.set(".text-label", { opacity: 0, y: 8 });
  gsap.set(".chart-fill", { opacity: 0 });
  gsap.set(chartLine, {
    strokeDasharray: lineLength,
    strokeDashoffset: lineLength,
  });

  document.querySelectorAll(".chart-dot").forEach((dot) => {
    const bbox = dot.getBBox();
    gsap.set(dot, {
      svgOrigin: `${bbox.x + bbox.width / 2} ${bbox.y + bbox.height / 2}`,
      scale: 0,
      opacity: 0,
    });
  });

  const tl = gsap.timeline({
    scrollTrigger: {
      trigger: svg,
      start: "top 80%",
      toggleActions: "play none none reverse",
    },
  });

  const dotPaths = gsap.utils.toArray(".chart-dot");
  const dotGroups = {};
  dotPaths.forEach((dot) => {
    const bbox = dot.getBBox();
    const cx = Math.round(bbox.x + bbox.width / 2);
    if (!dotGroups[cx]) dotGroups[cx] = [];
    dotGroups[cx].push(dot);
  });
  const groupedDots = Object.entries(dotGroups)
    .sort((a, b) => Number(a[0]) - Number(b[0]))
    .map(([, group]) => group);

  tl.to(".grid-line", { opacity: 1, duration: 0.6, ease: "power2.out" }).to(".text-label", { opacity: 1, y: 0, duration: 0.5, stagger: 0.04, ease: "power2.out" }, "-=0.3").to(chartLine, { strokeDashoffset: 0, duration: 2, ease: "power2.inOut" }, "-=0.4").to(".chart-fill", { opacity: 1, duration: 1.2, ease: "power2.out" }, "-=1.6");

  groupedDots.forEach((group, i) => {
    tl.to(
      group,
      {
        scale: 1,
        opacity: 1,
        duration: 0.5,
        ease: "back.out(2)",
      },
      i === 0 ? "-=1.4" : "-=0.2",
    );
  });
